mapper.select:
select * from ( select rownum rn, I.* from ( select L.lot_id as lotId, L.lot_item as lotItem, L.lot_vendor as lotVendor, L.lot_work as lotWork, L.lot_qty as lotQty, L.lot_fqty as lotFqty, L.lot_mfd as lotMfd, L.lot_etw as lotEtw, L.lot_exp as lotExp, L.lot_qc as lotQc, L.lot_status as lotStatus, L.lot_memo as lotMemo, L.lot_bwhsec as lotBwhsec, L.lot_awhsec as lotAwhsec, L.lot_cqty as lotCqty, IT.item_name as lotItemName from lot L LEFT JOIN ITEM IT ON L.LOT_ITEM = IT.ITEM_ID
AND lot_status = #{lotStatus}
AND ( UPPER(lot_id) LIKE UPPER('%' || #{searchKeyword} || '%') OR UPPER(lot_item) LIKE UPPER('%' || #{searchKeyword} || '%') OR UPPER(IT.item_name) LIKE UPPER('%' || #{searchKeyword} || '%') )
AND L.lot_exp >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND L.lot_exp < TO_DATE(#{endDate}, 'YYYY-MM-DD') + 1
ORDER BY lot_id DESC ) I ) WHERE RN BETWEEN #{page.startRow} AND #{page.endRow}

SELECT L.LOT_ID AS lotId, L.LOT_ITEM AS lotItem, L.LOT_VENDOR AS lotVendor, V.vendor_name as lotVendorName, L.LOT_WORK AS lotWork, L.LOT_QTY AS lotQty, L.LOT_FQTY AS lotFqty, L.LOT_MFD AS lotMfd, L.LOT_ETW AS lotEtw, L.LOT_EXP AS lotExp, L.LOT_QC AS lotQc, L.LOT_STATUS AS lotStatus, L.LOT_MEMO AS lotMemo, L.LOT_BWHSEC AS lotBwhsec, L.LOT_AWHSEC AS lotAwhsec, L.lot_cqty as lotCqty, I.ITEM_NAME AS lotItemName FROM LOT L LEFT JOIN ITEM I ON L.LOT_ITEM = I.ITEM_ID
LEFT JOIN VENDOR V ON L.LOT_VENDOR = V.VENDOR_ID
WHERE L.LOT_ID = #{lotId}
